        @Override
        public void onDescriptorWrite(BluetoothGatt gatt, BluetoothGattDescriptor descriptor, int status) {
            super.onDescriptorWrite(gatt, descriptor, status);
            long descriptorTime = System.currentTimeMillis();
            if (status == BluetoothGatt.GATT_SUCCESS) {
                android.util.Log.d("BLE_TIMING", "=== NOTIFICATIONS ENABLED at: " + descriptorTime + " ===");
                android.util.Log.d("BLE", "Notifications enabled successfully!");
            } else {
                android.util.Log.e("BLE_TIMING", "Failed to enable notifications at: " + descriptorTime);
                android.util.Log.e("BLE", "Failed to enable notifications, status: " + status);
            }
        }
    };

	void unsubscribe() {
    if (bluetoothGatt == null || service == null) {
        android.util.Log.e("BLE", "Cannot unsubscribe - not connected");
        return;
    }

    BluetoothGattCharacteristic feetDataChar = service.getCharacteristic(FEET_DATA_UUID);
    if (feetDataChar != null) {
        bluetoothGatt.setCharacteristicNotification(feetDataChar, false);

        BluetoothGattDescriptor descriptor = feetDataChar.getDescriptor(CCC_DESCRIPTOR_UUID);
        if (descriptor != null) {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                bluetoothGatt.writeDescriptor(descriptor, BluetoothGattDescriptor.DISABLE_NOTIFICATION_VALUE);
            } else {
                descriptor.setValue(BluetoothGattDescriptor.DISABLE_NOTIFICATION_VALUE);
                bluetoothGatt.writeDescriptor(descriptor);
            }
            android.util.Log.d("BLE", "Unsubscribe descriptor written");
        }
    }
}


    public void disconnect() {
		if (bluetoothGatt != null) {
			   if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
					if (ActivityCompat.checkSelfPermission(context,
						android.Manifest.permission.BLUETOOTH_CONNECT) != PackageManager.PERMISSION_GRANTED) {
						android.util.Log.e("BLE", "Missing BLUETOOTH_CONNECT permission");
						return;
					}
				}
			android.util.Log.e("BLE", "bluetoothGatt disconnect called");
			bluetoothGatt.close();  // close first
			bluetoothGatt.disconnect();
		}
	}

		public void resubscribe() {
		    if (bluetoothGatt != null) {
        android.util.Log.d("BLE", "Clearing cache and rediscovering services");
        service = null;
        characteristics = null;

        // Clear Android's GATT cache
        try {
            java.lang.reflect.Method refresh = bluetoothGatt.getClass().getMethod("refresh");
            if (refresh != null) {
                boolean refreshResult = (boolean) refresh.invoke(bluetoothGatt);
                android.util.Log.d("BLE", "Cache refresh result: " + refreshResult);
            }
        } catch (Exception e) {
            android.util.Log.e("BLE", "Cache refresh failed: " + e.getMessage());
        }

        bleHandler.postDelayed(new Runnable() {
            @Override
            public void run() {
                android.util.Log.d("BLE", "Calling discoverServices after cache clear");
                bluetoothGatt.discoverServices();
            }
        }, 300); // give cache clear time to complete
    } else {
        android.util.Log.e("BLE", "Cannot resubscribe - bluetoothGatt is null");
    }

	}

			}

		void Java_SendCentre(){
			if (bleManager != null) {
				bleManager.sendRecentreCharacteristic();
			}
		}

		void Java_SendReset(){
			if (bleManager != null) {
				bleManager.sendResetBoardCharacteristic();
			}
		}

		private boolean isConnected(BluetoothDevice device) {
			if (device == null) {
				return false;
			}

			// BLUETOOTH_CONNECT permission only exists on Android 12+
			if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
				if (ActivityCompat.checkSelfPermission(this,
					android.Manifest.permission.BLUETOOTH_CONNECT) != PackageManager.PERMISSION_GRANTED) {
					android.util.Log.e("BLE", "Missing BLUETOOTH_CONNECT permission in isConnected");
					return false;
				}
			}

			boolean bonded = device.getBondState() == BluetoothDevice.BOND_BONDED;
			android.util.Log.d("BLE", "Device bond state: " + device.getBondState());
			return bonded;
		}

    boolean Java_ConnectToBLEService() {
        BluetoothAdapter bluetoothAdapter = BluetoothAdapter.getDefaultAdapter();
		if (bleManager != null && bleManager.bluetoothGatt != null) {
			android.util.Log.d("BLE", "Already connected - resubscribing");
			bleManager.resubscribe();
			return true;
		}

		bleManager = null;


        if (bluetoothAdapter == null) {
            System.out.println("BLE: bluetoothAdapter == null");
            return false;
        } else if (!bluetoothAdapter.isEnabled()) {
            System.out.println("BLE: !bluetoothAdapter.isEnabled()");
            return false;
        }
        else {
			Set<BluetoothDevice> pairedDevices = bluetoothAdapter.getBondedDevices();
            for (BluetoothDevice device : pairedDevices) {
                String deviceName = device.getName();
                System.out.println("BLE:" + deviceName);
                if (deviceName != null && deviceName.startsWith("MotusVR")) {
                    System.out.println("BLE:" + "found");
                    if (isConnected(device)) {
                        deviceAddress = device.getAddress();
                        System.out.println("BLE: Motus Device Connected with address: " + deviceAddress);
                        Activity activity = (Activity) this;
						bleManager = new BLEManager(this, activity);
                        if(bleManager.connectToDevice(deviceAddress)){
                            System.out.println("BLE: Motus BLE Connected");
                            return true;
                        }else{
                            System.out.println("BLE: Motus BLE NOT!");
                            return false;
                        }
                    }
                }
            }
        }
        return false;
    }

gameActivityOnCreateAdditions.insert:

new Handler(Looper.getMainLooper()).postDelayed(new Runnable() {
    @Override
    public void run() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
            boolean needsBtConnect = ActivityCompat.checkSelfPermission(GameActivity.this,
                android.Manifest.permission.BLUETOOTH_CONNECT) != PackageManager.PERMISSION_GRANTED;
            boolean needsBtScan = ActivityCompat.checkSelfPermission(GameActivity.this,
                android.Manifest.permission.BLUETOOTH_SCAN) != PackageManager.PERMISSION_GRANTED;
            boolean needsLocation = ActivityCompat.checkSelfPermission(GameActivity.this,
                android.Manifest.permission.ACCESS_FINE_LOCATION) != PackageManager.PERMISSION_GRANTED;

            if (needsBtConnect || needsBtScan || needsLocation) {
                ActivityCompat.requestPermissions(GameActivity.this,
                    new String[]{
                        android.Manifest.permission.BLUETOOTH_CONNECT,
                        android.Manifest.permission.BLUETOOTH_SCAN,
                        android.Manifest.permission.ACCESS_FINE_LOCATION
                    }, 1);
            }
        } else {
            if (ActivityCompat.checkSelfPermission(GameActivity.this,
                android.Manifest.permission.ACCESS_FINE_LOCATION) != PackageManager.PERMISSION_GRANTED) {
                ActivityCompat.requestPermissions(GameActivity.this,
                    new String[]{
                        android.Manifest.permission.ACCESS_FINE_LOCATION
                    }, 1);
            }
        }
    }
}, 3000); // 3 second delay to let UE finish initialising

